import React from 'react';
import Home from '../../Pages/Home';
import Contact from "../../Pages/Contact";
import Gallery from "../../Pages/Gallery";
import Portfolio from "../../Pages/Portfolio";
import Error from "../../Pages/Error";

export interface Page {
    name: string
    element: React.ReactNode;
}

const Pages: Page[] = [
    {
        name: 'Contact',
        element: <Contact/>
    },
    {
        name: 'Gallery',
        element: <Gallery/>
    },
    {
        name: 'Portfolio',
        element: <Portfolio/>
    },
    {
        name: 'Home',
        element: <Home/>
    },
]

interface Route   {
    path: string,
    element: React.ReactNode,
  }

interface RouteMapper {
  getRoutes: () => Route[],
  getBaseRoutes: () => Route[],
}

const getBaseRoutes = () => Pages.map((e) => ({ path: e.name.toLowerCase(), element: e.element }));

const routeMapper: RouteMapper = {
    getBaseRoutes: getBaseRoutes,
    getRoutes: () => {
        const paths = getBaseRoutes()
        paths.push({path: '/', element: <Home/> })
        paths.push({path: '/*', element: <Error/> })
        return paths;
    },

}

export default routeMapper;
